package unverified;

import metadata.BehavioralDifference;
import metadata.DifferenceType;

import org.junit.jupiter.api.Test;

import static unverified.ClonePairGenericInvocationTestSupport.*;

class ClonePair5651DifferenceFindingTest {

    private final ClonePair5651 subject = new ClonePair5651();

    /**
     * Generated by Codex (GPT-5.5).
     * Difference type: return_value.
     * Difference manifestation: the methods return different values.
     */
    @Test
    @BehavioralDifference(DifferenceType.RETURN_VALUE)
    void methodsDisagreeOnGeneratedInput() {
        Object[] inputs = new Object[]{"1", false};
        InvocationOutcome method1Outcome = capture(values -> subject.method1((java.lang.String) values[0], ((Boolean) values[1]).booleanValue()), inputs);
        InvocationOutcome method2Outcome = capture(values -> subject.method2((java.lang.String) values[0], ((Boolean) values[1]).booleanValue()), inputs);

        assertCoreOutcome(
            method1Outcome,
            "OK",
            "Boolean(true)",
            null,
            "java.lang.Object[][String(MQ==),Boolean(false)]",
            "java.lang.Object[][String(MQ==),Boolean(false)]"
        );
        assertTextEquals("stdout", "", method1Outcome.stdout);
        assertTextEquals("stderr", "", method1Outcome.stderr);
        assertCoreOutcome(
            method2Outcome,
            "OK",
            "Boolean(false)",
            null,
            "java.lang.Object[][String(MQ==),Boolean(false)]",
            "java.lang.Object[][String(MQ==),Boolean(false)]"
        );
        assertTextEquals("stdout", "", method2Outcome.stdout);
        assertTextEquals("stderr", "", method2Outcome.stderr);
    }
}
